// Sacred Geometry — Fibonacci Spiral with Rotational Symmetry
// Adapted from GenerativeArtGallery / artwork9

let sgPhi = (1 + Math.sqrt(5)) / 2;
let sgBasePts = [];
let sgT = 0;
let sgPrevCount = '';

function sgBuild(count) {
  let pts = [];
  let baseR = 160;
  for (let i = 0; i < count; i++) {
    let angle = i * Math.PI * 2 * sgPhi;
    let r = baseR * Math.sqrt(i + 1) / Math.sqrt(count);
    pts.push({ angle: angle, baseR: r });
  }
  return pts;
}

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  sgBasePts = sgBuild(50);
};

p.draw = function() {
  let countStr = p.getSynthVar('point_count') || 'balanced';
  let symStr = p.getSynthVar('symmetry') || 'hexagon';
  let palStr = p.getSynthVar('color_palette') || 'gold';
  let speedStr = p.getSynthVar('motion_speed') || 'flowing';

  if (countStr !== sgPrevCount) {
    let n = countStr === 'sparse' ? 28 : countStr === 'balanced' ? 50 : 75;
    sgBasePts = sgBuild(n);
    sgPrevCount = countStr;
  }

  let sym = symStr === 'binary' ? 2 : symStr === 'quad' ? 4 : symStr === 'hexagon' ? 6 : 8;
  let spd = speedStr === 'meditative' ? 0.007 : speedStr === 'flowing' ? 0.016 : 0.038;

  let pals = {
    gold:      [45,  82, 95],
    celestial: [210, 68, 90],
    emerald:   [140, 80, 78],
    amethyst:  [278, 72, 86],
    sunset:    [18,  88, 95]
  };
  let pal = pals[palStr] || pals.gold;

  sgT += spd;
  p.background(240, 20, 6, 18);

  p.push();
  p.translate(p.width / 2, p.height / 2);

  let anim = sgBasePts.map(function(pt, i) {
    let osc = Math.sin(sgT + i * 0.22) * 9;
    let r = pt.baseR + osc;
    return { x: Math.cos(pt.angle) * r, y: Math.sin(pt.angle) * r, r: r };
  });

  for (let s = 0; s < sym; s++) {
    p.push();
    p.rotate(s * p.TWO_PI / sym + sgT * 0.08);

    for (let i = 0; i < anim.length; i++) {
      let lim = Math.min(anim.length, i + 10);
      for (let j = i + 1; j < lim; j++) {
        let dx = anim[i].x - anim[j].x;
        let dy = anim[i].y - anim[j].y;
        let d = Math.sqrt(dx * dx + dy * dy);
        if (d < 48) {
          let alpha = p.map(d, 0, 48, 55, 5);
          p.stroke(pal[0], pal[1] - 10, pal[2], alpha);
          p.strokeWeight(0.8);
          p.line(anim[i].x, anim[i].y, anim[j].x, anim[j].y);
        }
      }
    }

    p.noStroke();
    for (let i = 0; i < anim.length; i++) {
      let sz = p.map(anim[i].r, 0, 160, 2.5, 7);
      p.fill(pal[0], pal[1], pal[2], 88);
      p.ellipse(anim[i].x, anim[i].y, sz, sz);
    }

    p.pop();
  }

  p.pop();
};
